 3	import { NodeHealthCheck, UnhealthyCondition } from "data/types";
 4	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 5	import { map } from "lodash-es";
 6	
 7	export const UnhealthyConditionsTable: React.FC<{
 8	  nodeHealthCheck: NodeHealthCheck;
 9	}> = ({ nodeHealthCheck }) => {
